    [Fact]
    public void WFiltro_QuemCadHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var QuemCadValue = 1;
        var filtro = new FilterEscritorios
        {
            QuemCad = QuemCadValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroEscritorios(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var QuemCadParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBEscritoriosDicInfo.QuemCad}");
        QuemCadParameter.Should().NotBeNull();
        QuemCadParameter.Value.Should().Be(QuemCadValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBEscritoriosDicInfo.PTabelaNome}].[{DBEscritoriosDicInfo.QuemCad}] = @{DBEscritoriosDicInfo.QuemCad}");
    }

